queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?textbooks a :Textbooks .
    ?textbooks p:Title ?title .
    ?textbooks p:Difficulty_Level ?difficulty_level_f .
    FILTER(STR(?difficulty_level_f) = "Intermediate")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?online_courses a :Online_Courses .
    ?online_courses p:Course_Name ?course_name .
    ?online_courses p:Difficulty_Level ?difficulty_level_f .
    FILTER(STR(?difficulty_level_f) = "Intermediate")
    BIND(?course_name AS ?o0)
  }
}

